+						"-c",
+						fmt.Sprintf("i=0; while [ $i -lt %d ]; do dd if=/dev/urandom of=file${i} bs=1048576 count=1 2>/dev/null; sleep .1; i=$(($i+1)); done; while true; do sleep 5; done", diskConsumedMB),
+					},
+					Resources: sidecarResources,
+				},
+			},
+			Containers: []v1.Container{
+				{
